parameters.jsCode:
const raw = $input.first().json.output;
let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    score: "Warm",
    reasoning: "AI parsing failed — manual review recommended.",
    email_subject: "Thanks for visiting the open house!",
    email_body: `Hi ${$('Extract Visitor Details').first().json.visitorName},\n\nThank you for visiting the open house today. We would love to help you find the right property — please feel free to reach out at any time.`
  };
}

const visitorData = $('Extract Visitor Details').first().json;

function escapeHtml(text) {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function formatEmailHtml(text) {
  const paragraphs = text
    .split(/\n\s*\n/)
    .map(p => p.replace(/\s+/g, ' ').trim())
    .filter(Boolean);
  return paragraphs.map(p => `<p>${escapeHtml(p)}</p>`).join('');
}

return [{
  json: {
    ...visitorData,
    score: parsed.score,
    reasoning: parsed.reasoning,
    email_subject: parsed.email_subject,
    email_body: formatEmailHtml(parsed.email_body),
    recordId: `${visitorData.visitorEmail}-${Date.now()}`
  }
}];
